<?php
namespace Tests\Feature\Admin\Content;use App\Models\CombatBalanceSetting;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
final class CombatBalanceAdminTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();config(['game_admin.emails'=>['combat-admin@example.test']]);$this->admin=User::factory()->create(['email'=>'combat-admin@example.test']);}public function test_access_defaults_and_exact_percentage_update(){ $this->get(route('admin.content.combat-balance.index'))->assertRedirect('/login');$this->actingAs(User::factory()->create())->get(route('admin.content.combat-balance.index'))->assertForbidden();$this->actingAs($this->admin)->get(route('admin.content.combat-balance.index'))->assertOk()->assertSee('Balance defensivo');$this->put(route('admin.content.combat-balance.update'),['version'=>1,'defense_reduction_cap_percent'=>'70.25','absorb_damage_cap_percent'=>'60.50','total_mitigation_cap_percent'=>'90','minimum_damage'=>'2'])->assertSessionHasNoErrors();$s=CombatBalanceSetting::findOrFail(1);$this->assertSame(7025,$s->defense_reduction_cap_basis_points);$this->assertSame(6050,$s->absorb_damage_cap_basis_points);$this->assertSame(9000,$s->total_mitigation_cap_basis_points);$this->assertSame(2,$s->minimum_damage);$this->assertSame(2,$s->version);}public function test_invalid_and_stale_updates_are_rejected(){ $this->actingAs($this->admin)->put(route('admin.content.combat-balance.update'),['version'=>1,'defense_reduction_cap_percent'=>'100','absorb_damage_cap_percent'=>'0','total_mitigation_cap_percent'=>'90','minimum_damage'=>'1'])->assertSessionHasErrors();$this->put(route('admin.content.combat-balance.update'),['version'=>99,'defense_reduction_cap_percent'=>'70','absorb_damage_cap_percent'=>'70','total_mitigation_cap_percent'=>'90','minimum_damage'=>'1'])->assertSessionHasErrors('version');$this->assertSame(1,CombatBalanceSetting::findOrFail(1)->version);}}
